class Solution {
    public boolean isPalindrome(ListNode head) {
        if (head == null || head.next == null) {
            return true;
        }

        var slow = head;
        var fast = head;
        ListNode slowPrev = null;

        while (slow != null && fast != null && fast.next != null) {
            slowPrev = slow;
            slow = slow.next;
            fast = fast.next.next;
        }

        slowPrev.next = null;
        var reversed = reverse(slow);

        while (head != null) {
            if (head.val != reversed.val) {
                return false;
            }

            head = head.next;
            reversed = reversed.next;
        }

        return true;
    }

    private ListNode reverse(ListNode head) {
        ListNode prev = null;

        while (head != null) {
            var next = head.next;
            head.next = prev;
            prev = head;
            head = next;
        }

        return prev;
    }
}
